    plt.legend(loc='upper right', fontsize=24)
    ax1.grid(True, which="both")
    
    #fig.tight_layout()  # otherwise the right y-label is slightly clipped
    fig.set_size_inches(12,8)
    plt.savefig('throughput.png', dpi=200)
    plt.show()    
    

